/*
 * AQA A-Level English Language (7702) — Exam Practice Question Bank
 * All written / exam-style questions. 40 per topic, mark scales 2-25.
 * hasDiagram: true means the practice page should render a drawing canvas alongside
 *            the textarea so students can sketch a tree diagram, chart or annotated text.
 */

const ENGLISH_AQA_PRACTICE = {

  '1.1': {
    name: 'Methods of Language Analysis',
    questions: [
      /* ── Recall / basic application (Qs 1-15) ───────────────────────── */
      { q: 'State the six main linguistic levels / frameworks used to analyse texts at A-level.', marks: 6, markScheme: '• Phonetics, phonology and prosodics (1)\n• Graphology (1)\n• Lexis and semantics (1)\n• Grammar and morphology (1)\n• Pragmatics (1)\n• Discourse (1)' },
      { q: 'Define "lexis" and give one example of a lexical feature you might analyse.', marks: 2, markScheme: '• Lexis is the vocabulary / words used in a text (1)\n• Example lexical feature: register (formal vs informal), semantic fields, Anglo-Saxon vs Latinate origin, neologisms, slang, taboo lexis (1 mark for any valid example)' },
      { q: 'Define "graphology" and name two graphological features.', marks: 3, markScheme: '• Graphology is the visual appearance/layout of a text including typography, images and spatial arrangement (1)\n• Two features, e.g. font choice, colour, bold/italics, bullet points, headings, use of images, white space, columns (1 + 1)' },
      { q: 'State the difference between phonetics and phonology.', marks: 2, markScheme: '• Phonetics is the study of the physical production and articulation of speech sounds (1)\n• Phonology is the study of how sounds function meaningfully in a particular language system — the system of contrasts and patterns (1)' },
      { q: 'Define "morpheme" and distinguish between free and bound morphemes with one example of each.', marks: 4, markScheme: '• A morpheme is the smallest meaningful unit in language (1)\n• A free morpheme can stand alone as a word, e.g. "cat" / "run" (1)\n• A bound morpheme must attach to another morpheme, e.g. "-s" (plural), "un-" (prefix) (1)\n• Example breakdown: "unhappiness" = "un" (bound) + "happy" (free) + "ness" (bound) (1)' },
      { q: 'Identify and label the main elements of the following noun phrase: "those ancient wooden boats in the harbour".', marks: 5, markScheme: '• Determiner: "those" (1)\n• Pre-modifier (adjective): "ancient" (1)\n• Pre-modifier (adjective): "wooden" (1)\n• Head noun: "boats" (1)\n• Post-modifier (prepositional phrase): "in the harbour" (1)' },
      { q: 'Name and describe the four sentence functions.', marks: 4, markScheme: '• Declarative — makes a statement (1)\n• Interrogative — asks a question (1)\n• Imperative — gives a command / instruction (1)\n• Exclamatory — expresses strong feeling (1)' },
      { q: 'Classify the following as simple, compound or complex: (a) "The dog barked." (b) "The dog barked and the cat ran." (c) "When the doorbell rang, the dog barked."', marks: 3, markScheme: '• (a) Simple — one main clause with one finite verb (1)\n• (b) Compound — two main clauses joined by the coordinating conjunction "and" (1)\n• (c) Complex — main clause "the dog barked" + subordinate clause "when the doorbell rang" (1)' },
      { q: 'State what is meant by a "modal auxiliary verb" and give three examples.', marks: 4, markScheme: '• A modal is an auxiliary verb that expresses possibility, obligation, permission or necessity (1)\n• It is always followed by a bare infinitive and does not take -s in the third person (1)\n• Three examples from: can, could, may, might, must, shall, should, will, would (1 + 1)' },
      { q: 'Explain what is meant by "semantic field".', marks: 2, markScheme: '• A semantic field is a group of words with related meanings linked to a particular topic or domain (1)\n• Example: warfare — "battle", "attack", "defend", "troops"; identifying a semantic field shows the writer is framing the subject through that lens (1)' },
      { q: 'Define "denotation" and "connotation" using the example word "home".', marks: 3, markScheme: '• Denotation — the literal, dictionary definition: "the place where one lives" (1)\n• Connotation — the associations a word carries: warmth, belonging, safety, family (1)\n• Connotations can vary between individuals and cultures, so analysing them requires considering audience and context (1)' },
      { q: 'State what a "phoneme" is and give the phonemic difference between "pit" and "bit".', marks: 3, markScheme: '• A phoneme is the smallest unit of sound that can distinguish meaning in a language (1)\n• "Pit" begins with /p/ — a voiceless bilabial plosive; "bit" begins with /b/ — a voiced bilabial plosive (1)\n• The only contrast is voicing, yet it changes meaning — this shows /p/ and /b/ are separate phonemes in English (1)' },
      { q: 'Identify three prosodic features used in spoken discourse.', marks: 3, markScheme: '• Any three from: stress (syllable or word emphasis), intonation (pitch pattern), tempo (speed), pause, volume, rhythm (1 + 1 + 1)' },
      { q: 'Define "discourse" in the context of linguistic analysis.', marks: 2, markScheme: '• Discourse is language beyond the level of the sentence — connected extended stretches of spoken or written communication (1)\n• Analysis considers cohesion, organisation, turn-taking, openings/closings, and how texts position the audience (1)' },
      { q: 'State three common non-fluency features of spontaneous speech.', marks: 3, markScheme: '• Any three from: fillers (er, um), false starts, repetitions, repairs, unintentional pauses, incomplete utterances (1 + 1 + 1)' },

      /* ── Analytical application (Qs 16-30) ──────────────────────────── */
      { q: 'The following sentence contains a subordinate clause: "Although it was raining, the match continued." Identify the subordinate clause and explain its grammatical function.', marks: 3, markScheme: '• Subordinate clause: "Although it was raining" (1)\n• Function: adverbial clause of concession — modifies the main clause (1)\n• Introduced by the subordinating conjunction "although"; cannot stand alone as a complete sentence (1)' },
      { q: 'Analyse the effect of the graphological features in a hypothetical tabloid front page that uses all-capital headlines, large white-on-red typography, and a single full-bleed image.', marks: 6, markScheme: '• All-capital headlines: visually foregrounded, suggesting urgency and volume, analogous to shouting (1)\n• White-on-red: high contrast maximises attention and connotes alarm, danger, controversy (1)\n• Large type size: forces the main story to dominate the page, prioritising emotional impact over information hierarchy (1)\n• Full-bleed image: immersive and emotive, positioning the reader affectively rather than analytically (1)\n• Together these choices construct a sensationalist register typical of mass-market press (1)\n• The graphology works with lexis (monosyllabic, emotive) to construct a popular, interpersonal style — audience positioning is immediate and visceral (1)' },
      { q: 'Explain how Grice\'s Cooperative Principle can be used to analyse the following exchange:\nA: "Did you enjoy the meal?"\nB: "Well… the plates were warm."', marks: 6, markScheme: '• Grice proposed that speakers cooperate via four maxims: quantity, quality, relation, manner (1)\n• B\'s response appears to flout the maxim of relation — praising the plates rather than the meal (1)\n• It also flouts quantity by providing less than expected (1)\n• This generates an implicature: B did not enjoy the meal but avoids a face-threatening direct criticism (1)\n• The hedging filler "well…" signals reluctance, reinforcing the negative implicature (1)\n• Thus pragmatics shows how cooperative speakers communicate meaning indirectly to preserve face — Grice + Brown and Levinson work together (1)' },
      { q: 'Analyse the following spoken extract using non-fluency features and turn-taking:\n"(.) so like I was (.) I was (.) kind of? (2) thinking we could um (.) maybe go out?"', marks: 5, markScheme: '• Micropauses "(.)" and a long 2-second pause "(2)" — planning time, hesitation (1)\n• Repetition "I was (.) I was" — false start / self-repair (1)\n• Hedge "kind of" and filler "um" — tentativeness, softening the suggestion (1)\n• Rising intonation marked by "?" on "kind of? / out?" — uptalk, checking the listener\'s agreement (1)\n• Overall effect: an uncommitted, polite invitation; interpersonally face-saving and cautious, typical of an informal request (1)' },
      { q: 'Identify and evaluate the rhetorical effect of the imperatives in a public-information poster that reads: "Wash your hands. Cover your mouth. Protect the NHS."', marks: 6, markScheme: '• Three imperatives in a triadic structure — memorability and rhythm (1)\n• Direct address via the implied "you" — creates urgency and personal responsibility (1)\n• The first two imperatives are specific and physical (hands, mouth), the third is abstract and moral (NHS) — scale escalates from self to national (1)\n• Simple, monosyllabic Anglo-Saxon lexis — accessible to the widest possible audience (1)\n• Short declarative-free clauses — unambiguous, reducing cognitive load during a public-health crisis (1)\n• The directive register positions the state as authoritative yet caring — effective for behaviour change, though some audiences may interpret imperatives as patronising (1)' },
      { q: 'Analyse the morphological structure of the words "unforgettable", "restarting" and "happiness".', marks: 6, markScheme: '• "Unforgettable": "un-" (bound prefix, negation) + "forget" (free root) + "-able" (bound suffix, adjectival) — derivational morphology (1 + 1)\n• "Restarting": "re-" (bound prefix, repetition) + "start" (free root) + "-ing" (bound inflectional suffix, progressive) (1 + 1)\n• "Happiness": "happy" (free root) + "-ness" (bound suffix — converts adjective to noun); note the orthographic change y→i (1 + 1)' },
      { q: 'Identify and explain three features of written mode that would be unusual in spontaneous spoken discourse.', marks: 6, markScheme: '• Complex embedded clauses / subordination — planned written prose can hold multiple layers, whereas speech tends to be coordinated (1 + 1)\n• Precise punctuation and paragraph breaks — speech uses prosody and pauses instead (1 + 1)\n• Formal register / Latinate lexis — written texts can retrieve and edit vocabulary; speech uses higher-frequency Anglo-Saxon words (1 + 1)' },
      { q: 'A child aged 4 says "I buyed two sweets at the shop." Identify the morphological error and explain what it reveals about language acquisition.', marks: 4, markScheme: '• Error: past tense "buyed" instead of the irregular form "bought" (1)\n• This is a virtuous error — the child has overgeneralised the regular past-tense morpheme "-ed" (1)\n• It suggests the child has internalised a rule rather than learning by imitation (1)\n• Evidence for nativist / rule-based theories of acquisition (Chomsky) over purely behaviourist (Skinner) accounts (1)' },
      { q: 'Compare the register used in:\n(a) "It is regrettable that we must decline your application."\n(b) "Sorry, no dice."', marks: 6, markScheme: '• (a) Formal register: Latinate lexis ("regrettable", "decline", "application"), impersonal declarative, complex syntax, passive-like framing (1 + 1)\n• (b) Informal register: colloquial idiom "no dice", monosyllabic Anglo-Saxon lexis, elliptical sentence without subject or verb (1 + 1)\n• Both communicate the same denotative refusal but differ pragmatically: (a) preserves face through formality; (b) assumes close social distance and is more direct (1)\n• Choice of register depends on audience, purpose, mode — same message, different effects on the relationship (1)' },
      { q: 'The following sentence contains a passive construction: "The building was demolished by the council last year." Rewrite it in the active voice and explain why a writer might choose the passive.', marks: 4, markScheme: '• Active: "The council demolished the building last year." (1)\n• Passive foregrounds the patient (the building) and backgrounds the agent (the council) (1)\n• Writers choose passive to obscure agency (avoiding blame), to emphasise what was done, or to sound formal/impersonal (e.g. scientific writing) (1)\n• Thus grammar is never neutral — the choice of active vs passive shapes representation (1)' },
      { q: 'Label the word-class of each underlined word in: "The very small dog quickly chased three cats."', marks: 7, markScheme: '• "The" — determiner (1)\n• "very" — adverb (modifying adjective) (1)\n• "small" — adjective (1)\n• "dog" — noun (1)\n• "quickly" — adverb (modifying verb) (1)\n• "chased" — verb (past tense) (1)\n• "three" — determiner/numeral; "cats" — noun (1 for either)' },
      { q: 'Explain the difference between "homophones", "homographs" and "homonyms" with an example of each.', marks: 6, markScheme: '• Homophones — same sound, different meaning and often different spelling, e.g. "pair" / "pear" (1 + 1)\n• Homographs — same spelling, different meaning/pronunciation, e.g. "lead" (metal) / "lead" (to guide) (1 + 1)\n• Homonyms — same spelling AND sound, different meaning, e.g. "bat" (animal) / "bat" (for cricket) (1 + 1)' },
      { q: 'Identify three cohesive devices in the following paragraph:\n"Harriet bought a new phone. It had a large screen. Although she was pleased, she worried about the battery."', marks: 4, markScheme: '• Pronoun reference: "it" (referring back to phone), "she" (referring back to Harriet) — anaphoric reference (1 + 1)\n• Lexical cohesion: repetition of semantic field (phone → screen → battery) (1)\n• Connective: "although" signalling concessive relationship (1)' },
      { q: 'Explain the effect of the foregrounding / marked word order in: "Never before have I seen such bravery."', marks: 4, markScheme: '• The sentence begins with the negative adverbial "Never before" — fronting (1)\n• This triggers subject-auxiliary inversion "have I seen" (1)\n• The inversion draws attention and adds rhetorical weight, often used in formal or literary register (1)\n• Foregrounding: unusual order signals emphasis; cf. unmarked "I have never seen such bravery" (1)' },
      { q: 'Identify three features of a scripted speech that mark it as "written to be spoken".', marks: 6, markScheme: '• Triadic / rule-of-three structures — "we cannot, we will not, we must not" — rhythm for spoken delivery (1 + 1)\n• Direct address ("you", "we") — simulates interpersonal engagement (1)\n• Short declarative sentences interspersed with longer ones — easier to deliver and land aloud (1)\n• Parallelism and repetition — aids recall for both speaker and audience (1)\n• Rhetorical questions — performative turn-taking (1)' },

      /* ── Extended / essay-style (Qs 31-40) ──────────────────────────── */
      { q: 'Analyse how the following advert constructs an authoritative register. Imagine a poster reading:\n"NEW. ULTRA-THIN. ENGINEERED IN GERMANY. Pre-order today."\nComment on lexis, graphology and syntax.', marks: 10, markScheme: '• Lexis: monosyllabic, adjectival, technology-adjacent lexis "ultra-thin" signals precision (1). Proper noun "Germany" invokes cultural stereotypes of engineering quality (1). Verb "engineered" (participle) nominalises process, backgrounding agency (1).\n• Graphology: full capitalisation signals brand voice, authority (1). Full stops between fragments simulate emphatic delivery (1).\n• Syntax: minor sentences and noun-phrase fragments (no finite verbs) — assertive, almost manifesto-like (1). Imperative "Pre-order" directly addresses the consumer, creating urgency (1).\n• Register: the absence of personal pronouns plus the Latinate "engineered" construct an impersonal, confident authority (1).\n• The register positions the consumer as a discerning admirer rather than a target — a strategy common in premium-brand advertising (1).\n• Overall effect: authority is constructed through the combination of frameworks, not any single feature — integrating levels is essential to a full-mark answer (1).' },
      { q: 'Analyse the spoken extract below for Grice\'s maxims and Brown & Levinson\'s politeness theory:\nBoss: "So about the deadline…"\nEmployee: "Right, right, absolutely. I\'m basically almost done."', marks: 10, markScheme: '• Grice — Quantity: employee provides vague quantifiers ("basically", "almost") rather than precise information — flouting quantity (1).\n• Quality: the hedges suggest the truth is being softened — possible flouting of quality, hinting the work is not done (1).\n• Manner: the repetition "right, right" and string of hedges is ambiguous and lacks orderliness — flouts manner (1).\n• Relation: the response stays on topic so relation is observed (1).\n• Brown & Levinson: the employee is protecting the boss\'s positive face (appearing cooperative and agreeable) and their own negative face (buying time without committing) (1 + 1).\n• "Right, right, absolutely" — agreement tokens that support positive face (1).\n• Hedging ("basically", "almost") — negative-face strategies limiting commitment (1).\n• The boss\'s unfinished turn "So about the deadline…" is itself indirect, allowing face-saving (1).\n• Overall: pragmatic frameworks reveal the implicit power dynamics and face-work, which are invisible if we only analyse lexis or syntax (1).' },
      { q: 'Write an analytical commentary on how a writer might use fronting, passive voice and nominalisation to create a formal, impersonal register. Illustrate with invented examples.', marks: 12, markScheme: '• Define fronting: moving a non-subject element to sentence-initial position for emphasis, e.g. "At the heart of the matter lies a single principle." (1 + 1)\n• Define passive: agent demotion, e.g. "Mistakes were made" rather than "The company made mistakes" (1 + 1)\n• Define nominalisation: turning processes/actions into nouns, e.g. "The implementation of the new policy" rather than "implementing the policy" (1 + 1)\n• All three distance the writer from direct agency, foregrounding abstract concepts over human actors (1).\n• Typical contexts: academic writing, legal texts, government reports, corporate communications (1).\n• Effect on audience: constructs authority and objectivity; can also obscure responsibility — the ethical implication of "neutral" grammar (1).\n• Integration: these syntactic choices interact with Latinate lexis and subordinated structure to produce register (1).\n• Counterpoint: overuse can feel evasive or dehumanising, a feature critics of "Plain English" campaigns highlight (1).\n• Conclusion: the choice is never merely stylistic — each option represents and positions differently, showing grammar is a meaning-making system (1).' },
      { q: 'Discuss the claim: "Phonology and graphology are superficial features; meaning lies in lexis and grammar." Evaluate using examples. [15 marks]', marks: 15, markScheme: '• Acknowledge the claim: at first glance sound and visual design seem secondary to words and structure (1).\n• Counter-example: poetry — metre, rhyme, assonance, alliteration ARE the meaning; they cannot be separated from content (1 + 1).\n• Counter-example: advertising slogans — rhythm ("Beanz Meanz Heinz") and alliteration create memorability that lexis alone cannot explain (1 + 1).\n• Graphology: typography in political propaganda (e.g. font, colour) communicates ideology before the reader processes lexis (1 + 1).\n• Spoken discourse: prosodic features (stress, intonation) can reverse literal meaning — "Oh, THAT\'S nice" with falling stressed intonation signals sarcasm (1 + 1).\n• Integration: the six levels are interlocking — ignoring phonology/graphology misses how a text speaks to a sense modality (1).\n• However: for purely informational texts (recipes, technical manuals), phonology is minimal and graphology functions instrumentally (1).\n• Theorised perspective: Halliday\'s metafunctions — ideational (content), interpersonal (relationship), textual (organisation) — the textual metafunction includes graphology (1).\n• Evaluation: the claim under-values semiotic channels; multi-modal texts demand multi-modal analysis (1).\n• Conclusion: rather than "superficial", phonology and graphology are where the text is embodied in sound and sight — a linguistically complete analysis integrates all six levels (1 + 1).' },
      { q: 'Describe Halliday\'s three metafunctions of language and apply them to a short invented example of a restaurant menu.', marks: 10, markScheme: '• Ideational — represents experience / content; menu uses noun phrases "slow-roasted lamb shank" to construct reality of food (1 + 1)\n• Interpersonal — enacts relationships; menu register ("our chef recommends…") positions reader as valued customer (1 + 1)\n• Textual — organises the message; menu uses sections (starters, mains), typography, layout to guide navigation (1 + 1)\n• Example sentence: "Our award-winning sommelier is delighted to suggest a pairing of Côtes du Rhône." — ideational (suggests wine), interpersonal (deferential to customer, authoritative brand voice), textual (placement after each main course) (1 + 1)\n• Halliday\'s framework forces the analyst to ask what the text represents, how it constructs the relationship, and how it is organised — three questions at once (1)\n• The integration mirrors the way the examiner expects students to see lexis + grammar + graphology as a single communicative act (1)' },
      { q: 'Using the phonetic transcription, explain the difference in articulation between the initial sounds of "ship" /ʃɪp/ and "chip" /tʃɪp/.', marks: 6, markScheme: '• /ʃ/ — voiceless postalveolar fricative — continuous turbulent airflow (1 + 1)\n• /tʃ/ — voiceless postalveolar affricate — begins with a plosive /t/ release into a fricative /ʃ/ (1 + 1)\n• Phonemic distinction: the minimal pair "ship" / "chip" differs only in this initial phoneme (1)\n• Importance: shows that English\'s phoneme inventory distinguishes stops, fricatives and affricates, and that orthography ("sh" vs "ch") does not map one-to-one onto sound (1)' },
      { q: 'Analyse the effect of lexis and syntax in the following opening of a 19th-century novel (invented): "It was in the bleak December of 18–, under a sky the colour of bruised iron, that I first perceived the extraordinary figure of Mr. Lawton."', marks: 10, markScheme: '• Opening with a cleft construction "It was… that I first perceived" — fronts the setting, suspending the subject and delaying information (1 + 1)\n• Archaic lexical choices "bleak", "perceived", elevated register (1)\n• Elaborated noun phrase "the extraordinary figure of Mr. Lawton" with post-modifying prepositional phrase — mystery, introduction of a key character (1 + 1)\n• Metaphor "sky the colour of bruised iron" — synaesthesia mixing visual and tactile, connotations of violence and weathered history (1)\n• Elided year "18–" — typographical convention creating verisimilitude, pseudo-historical distance (1)\n• Hypotactic syntax with embedded subordinate phrases mirrors Victorian prose style (1)\n• Register: Latinate lexis, formal syntax, narrator positioned as retrospective and educated (1)\n• Cumulatively: grammar + lexis + graphology construct a genre-specific atmosphere — the text announces "this is a 19th-century literary novel" through form before content (1)' },
      { q: 'Define deixis and analyse the deictic expressions in: "I\'ll see you here tomorrow." [Context: one friend speaking to another at a café on Monday evening.]', marks: 8, markScheme: '• Deixis: words whose reference depends on the context of utterance — speaker, hearer, place, time (1 + 1)\n• "I" — personal deixis, refers to the speaker (1)\n• "you" — personal deixis, refers to the hearer/friend (1)\n• "here" — spatial deixis, refers to the café (1)\n• "tomorrow" — temporal deixis, relative to Monday evening → Tuesday (1)\n• Deictic reference is economical but utterly dependent on shared context; an outsider reading the transcript alone cannot interpret it (1)\n• This is why pragmatic analysis requires situational context: the same utterance at a different time/place refers to different entities (1)' },
      { q: 'Explain what is meant by a "minor sentence" and discuss three contexts in which minor sentences are commonly used.', marks: 8, markScheme: '• A minor sentence lacks a finite verb and/or an explicit subject — e.g. "Fantastic." / "Why?" / "Exit here." (1 + 1)\n• Context 1: headlines — e.g. "Champions again." — brevity and impact (1 + 1)\n• Context 2: advertising — "Because you\'re worth it." — foregrounds brand voice (1 + 1)\n• Context 3: spontaneous speech — ellipsis recovers information from context: A: "Coming tomorrow?" B: "Yep." (1 + 1)\n• Minor sentences show that grammaticality is about communicative effectiveness, not rigid subject-verb completeness — they are highly context-dependent and interpersonally rich (1)' },
      { q: 'Analyse how the six linguistic frameworks might combine to explain the distinctive register of a political speech delivered to a large public audience. [25 marks — A-level extended essay]', marks: 25, markScheme: 'Award up to 25 marks for integrated, example-led analysis. Indicative points:\n• Phonology/prosodics: triadic rhythm, stressed content words, strategic pauses build delivery (2)\n• Graphology (in the written version): paragraphing, emphasis, layout cues for spoken delivery (2)\n• Lexis: mix of abstract Latinate ("democracy", "liberty") and concrete Anglo-Saxon ("home", "work") — positioning speaker as elevated yet relatable (2 + 2)\n• Grammar: fronted adverbials ("Today, we stand…"), parallelism, short declaratives following long subordinate clauses — creating rhetorical peaks (2 + 2)\n• Pragmatics: inclusive "we" — builds positive face of the audience; imperatives softened by modal "should" — negative-face politeness (2 + 2)\n• Discourse: openings ("My fellow citizens"), closings ("God bless us all") as genre markers; use of anecdote → principle → call to action as discourse structure (2 + 2)\n• Theoretical integration: Halliday\'s metafunctions map onto the six frameworks — ideational (content), interpersonal (audience positioning), textual (cohesion of the speech) (2)\n• Evaluation: each framework gives partial insight; the register exists in the interplay. A speech analysed lexically only misses why it feels like a speech (2)\n• Contextual awareness: genre conventions (State of the Union, party conference) constrain and license specific moves — showing AO3 engagement (1)\n• Conclusion: the six frameworks are a toolkit; genuine analysis blends them to show how meaning and effect are co-constructed across levels (2)' },
    ],
  },

  '1.2': {
    name: 'Textual Variations and Representations',
    questions: [
      { q: 'Define the terms "mode", "audience", "purpose" and "genre" as they are used in language analysis.', marks: 4, markScheme: '• Mode: channel — spoken, written, electronic, multimodal (1)\n• Audience: intended readers/listeners of a text (1)\n• Purpose: the reason the text was produced (inform, persuade, entertain, instruct, express…) (1)\n• Genre: conventional text type with recognised features (recipe, news report, obituary, advert…) (1)' },
      { q: 'Identify three features typical of written mode that would not usually appear in spontaneous speech.', marks: 3, markScheme: '• Paragraphing / sub-headings (1)\n• Subordinated, edited complex sentences (1)\n• Consistent punctuation and standardised spelling (1)' },
      { q: 'Identify three features of spontaneous spoken mode that would not typically appear in a planned written text.', marks: 3, markScheme: '• Non-fluency features: fillers (er, um), false starts, repairs (1)\n• Deictic pronouns that depend on the shared situation (1)\n• Ellipsis + phatic / interactional tokens ("yeah", "right") (1)' },
      { q: 'Explain what "register" means and give two linguistic factors that contribute to register.', marks: 4, markScheme: '• Register = the level of formality/appropriateness of language to a given context (1)\n• Lexis (formal Latinate vs informal Anglo-Saxon) (1)\n• Grammar (complex subordination vs simple coordination, passive vs active) (1)\n• Plus graphology / pragmatics; two valid examples sufficient (1)' },
      { q: 'A charity advert uses the headline "YOU can save a life TODAY." Identify two persuasive features and explain their effects.', marks: 4, markScheme: '• Capitalised "YOU" — second-person direct address foregrounds the reader and creates personal responsibility (1)\n• Capitalised "TODAY" — graphological foregrounding emphasising urgency (1)\n• Modal / dynamic verb "can save" — constructs the reader as capable agent (1)\n• Fragmented minor sentence punctuation adds immediacy (1)' },
      { q: 'State Jakobson\'s six functions of language.', marks: 6, markScheme: '• Referential (content / world) (1)\n• Emotive / expressive (speaker feelings) (1)\n• Conative (audience / persuasion) (1)\n• Phatic (maintaining contact / relationship) (1)\n• Metalingual (talking about language itself) (1)\n• Poetic / aesthetic (form / style) (1)' },
      { q: 'Explain what is meant by "representation" and give two examples of how it operates in language.', marks: 4, markScheme: '• Representation = how language constructs a particular version of reality (people, events, groups) (1)\n• Lexical choice encoding evaluation (e.g. "rebels" vs "freedom fighters") (1)\n• Grammatical choice shaping agency (e.g. passive voice hiding the agent) (1)\n• Representation is ideological — always a version, never neutral (1)' },
      { q: 'Identify three features that distinguish a tabloid newspaper register from a broadsheet register.', marks: 6, markScheme: '• Tabloid: monosyllabic Anglo-Saxon lexis; large emotive headlines; puns and alliteration (1 + 1)\n• Broadsheet: Latinate vocabulary; longer, more complex sentences; denser noun phrases (1 + 1)\n• Tabloid: direct address and personal human-interest angles (1)\n• Broadsheet: more detached third-person reporting and expert quotation (1)' },
      { q: 'Explain Fairclough\'s distinction between "instrumental" and "influential" power, with one example of each.', marks: 4, markScheme: '• Instrumental power — authority enforced by institutions (law, contracts, police) (1)\n• Example: a court summons using formal archaic lexis and imperatives (1)\n• Influential power — persuasion via media, advertising, political rhetoric (1)\n• Example: an advert using inclusive "we" and rhetorical questions (1)' },
      { q: 'Analyse the following political slogan for representation and persuasive technique: "Take back control."', marks: 6, markScheme: '• Imperative verb "take" — directive, calling the audience to action (1)\n• "Back" implies the control was once held — presupposition / representation of loss (1)\n• "Control" is an abstract nominalisation — broad, ideologically flexible (can mean many things to different voters) (1)\n• Three-word triad — memorable rhythm (phonology) (1)\n• Ellipsis of subject "you" — makes it universal / inclusive (1)\n• Therefore a compressed slogan encoding ideology in lexis, grammar and phonology simultaneously (1)' },
      { q: 'Identify three features of a text that would suggest a young-child audience.', marks: 3, markScheme: '• Simple sentences / coordination (1)\n• Concrete, monosyllabic lexis; rhyme / alliteration (1)\n• Imperatives or direct address; illustrations integrated with text (1)' },
      { q: 'Describe three conventions of the genre "news report" and one way a specific text might deviate from them.', marks: 4, markScheme: '• Inverted pyramid: most important information first (1)\n• Headline + byline + lead paragraph structure (1)\n• Third-person, apparent objectivity, direct quotation (1)\n• Deviation: a columnist piece using first person, rhetorical questions and evaluative lexis (1)' },
      { q: 'Compare the graphological features of a printed newspaper front page and a news website homepage.', marks: 6, markScheme: '• Print: fixed layout, single large headline + photograph, columns (1)\n• Digital: dynamic layout, multiple headlines, hyperlinks, video (1)\n• Print: limited by page size → hierarchy established through typography alone (1)\n• Digital: hierarchy via position, size AND engagement metrics (trending, "most read") (1)\n• Both use typography to signal register, but digital uses interactive affordances — fundamentally multimodal (1)\n• Reader experience differs: linear/curated (print) vs non-linear/personalised (digital) (1)' },
      { q: 'Explain what "synthetic personalisation" is and give an example from advertising.', marks: 4, markScheme: '• Synthetic personalisation (Fairclough) — use of intimate/inclusive language to simulate a personal relationship with a mass audience (1)\n• Uses inclusive "we", second-person "you", first-name brand voices (1)\n• Example: "We know you\'re busy. That\'s why we\'ve made ordering easier." (1)\n• Effect: the reader is positioned as individually known and cared for — increases brand affinity (1)' },
      { q: 'A recruitment advert uses imperatives, rhetorical questions, bullet points and inclusive "we". Analyse the text\'s register and persuasive strategy.', marks: 8, markScheme: '• Imperatives ("apply", "join us") — direct, action-oriented (1)\n• Rhetorical questions ("Ready for a new challenge?") — engage the reader\'s self-image (1)\n• Bullet points — textual metafunction: scannable, clear benefits (1)\n• Inclusive "we" — synthetic personalisation, positioning the company as already intimate with the candidate (1)\n• Register: semi-formal — business credibility mixed with interpersonal warmth (1)\n• Genre: recruitment copy — conventional combination of informational + persuasive functions (1)\n• Effect: flatters candidate, reduces perceived distance, builds positive face (Brown &amp; Levinson) (1)\n• Integrated analysis across lexis, grammar, graphology and pragmatics (1)' },
      { q: 'Identify and analyse three features of online discussion forums (e.g. Reddit threads) that reflect hybrid mode.', marks: 6, markScheme: '• Written but turn-taking — threaded replies function like conversation (1 + 1)\n• Emoji and punctuation substitute for prosodic/paralinguistic cues (1 + 1)\n• Register mixes formal content discussion with informal "LOL", hedging, in-group slang (1 + 1)' },
      { q: 'Explain the concept of "discourse community" and give an example.', marks: 4, markScheme: '• A discourse community is a group that shares communicative conventions and goals in a particular field or activity (Swales) (1)\n• Shared lexis / jargon / typical genres / shared knowledge (1)\n• Example: medical professionals — drug names, dosages, SOAP notes (1)\n• Joining a discourse community involves learning its registers (1)' },
      { q: 'Compare the representation of a social group in a broadsheet article with a tabloid article on the same event.', marks: 10, markScheme: '• Broadsheet: precise nouns ("protesters", "campaigners"), expert quotation, complex syntax, balanced viewpoints (1 + 1 + 1)\n• Tabloid: emotive labels ("mob", "thugs"), rhetorical questions, short declaratives, foregrounded shock (1 + 1 + 1)\n• Representation: same event constructed as democratic expression vs threat to order (1 + 1)\n• Fairclough: media discourse reproduces and shapes ideology (1)\n• Synthesis: lexical + grammatical + graphological choices ALL contribute to representation — no neutral reporting (1)' },
      { q: 'Analyse how a politician might use modality, inclusive pronouns and passive voice in a public speech to manage their representation.', marks: 10, markScheme: '• Modality: "we must", "we will" — strong obligation/prediction signals confidence and duty (1 + 1)\n• Inclusive "we": positions the speaker alongside the audience (1 + 1)\n• Passive voice when discussing unpopular actions: "reforms were introduced" — obscures agency (1 + 1)\n• Together these construct a leader who is decisive (modality), unifying (pronouns) and distanced from negatives (passive) (1 + 1)\n• Integrated across grammar + pragmatics — encoding ideology through everyday grammatical choices (1 + 1)' },
      { q: 'Write an analytical commentary on how the following text uses lexis, grammar, graphology and pragmatics to construct a particular representation of a social group. Use an invented tabloid front-page extract of your own: "BRITAIN INVADED — migrants flood south coast as PM dithers". [20 marks]', marks: 20, markScheme: 'Indicative points, up to 20:\n• Lexis — "invaded" (military connotations), "flood" (natural disaster metaphor), "dithers" (evaluative, colloquial); semantic field of threat + incompetence (3)\n• Grammar — passive-like "invaded" foregrounds the country as victim; present tense "dithers" makes the problem immediate (3)\n• Graphology — all caps, large type, combative layout; tabloid conventions (3)\n• Pragmatics — presupposes that migration = invasion, encoding ideology; positions reader as nationally threatened (3)\n• Genre convention — tabloid front page prioritises emotional impact over nuance (2)\n• Representation — migrants constructed as homogeneous threatening mass; government as weak (2)\n• Contextual factors — broader media representation of migration, political moment (2)\n• Evaluation — alternative lexical choices available ("arrivals", "asylum seekers") would produce different representation; lexis is ideological (2)' },
    ],
  },

  '1.3': {
    name: "Children's Spoken Language Development",
    questions: [
      { q: 'Name and describe the four main stages of children\'s spoken language development.', marks: 4, markScheme: '• Pre-verbal (0–12m): cooing, babbling, no words (1)\n• Holophrastic (12–18m): single words standing for whole ideas (1)\n• Two-word (18–24m): two-word utterances such as "daddy gone" (1)\n• Telegraphic / post-telegraphic (2–5y): content-heavy short utterances developing into full grammar (1)' },
      { q: 'Describe Halliday\'s seven functions of language with brief examples.', marks: 7, markScheme: '• Instrumental — getting things: "want juice" (1)\n• Regulatory — controlling others: "no bed" (1)\n• Interactional — social relationships: "hi nanny" (1)\n• Personal — expressing feelings: "me happy" (1)\n• Heuristic — exploring/learning: "what\'s that?" (1)\n• Imaginative — play/fantasy: "I\'m a dragon" (1)\n• Representational — giving information: "doggy barking" (1)' },
      { q: 'Explain what child-directed speech (CDS) is and give three typical features.', marks: 4, markScheme: '• CDS (motherese/parentese) is the register adults use with infants (1)\n• Higher pitch + exaggerated intonation (1)\n• Slower pace, clearer articulation, repetition (1)\n• Simplified vocabulary + questioning to invite turns (1)' },
      { q: 'State the behaviourist theory of acquisition (Skinner) and give one criticism.', marks: 4, markScheme: '• Skinner: children learn language through imitation, reinforcement and conditioning (1)\n• Positive reinforcement when utterances are "correct" strengthens the behaviour (1)\n• Criticism: behaviourism cannot explain virtuous errors (e.g. "goed") which the child has never heard (1)\n• Criticism: children produce novel combinations they have not been modelled — suggests internal rules, not pure imitation (1)' },
      { q: 'Describe Chomsky\'s nativist theory and two pieces of evidence for it.', marks: 5, markScheme: '• Chomsky: children are born with an innate Language Acquisition Device (LAD) enabling rapid grammar acquisition (1)\n• Universal features across languages suggest an innate Universal Grammar (1)\n• Evidence: virtuous errors show rule-following, not imitation (1)\n• Evidence: poverty of the stimulus — input is incomplete and inconsistent, yet children converge on full grammar (1)\n• Evidence: critical period — language acquisition becomes much harder after puberty (1)' },
      { q: 'Describe the case of Genie and explain what it suggests about the critical period hypothesis.', marks: 5, markScheme: '• Genie was a girl isolated from human interaction until about age 13 (1)\n• When discovered she had no language (1)\n• She subsequently acquired substantial lexis but never mastered complex grammar (1)\n• Supports Lenneberg\'s critical period hypothesis — first language acquisition is severely impaired after puberty (1)\n• Evaluation: single case; other factors (trauma) may confound interpretation — caution in generalising (1)' },
      { q: 'Describe Bruner\'s LASS and give a concrete example.', marks: 4, markScheme: '• Language Acquisition Support System — the interactional scaffolding caregivers provide (1)\n• Joint attention: caregiver and child attend to the same object together (1)\n• Example: the picture-book routine — parent points, names, pauses, waits for child\'s contribution (1)\n• Complements Chomsky\'s LAD — innate capacity realised in rich input (1)' },
      { q: 'Explain Piaget\'s cognitive theory of language acquisition.', marks: 4, markScheme: '• Piaget: language development is linked to cognitive development (1)\n• Children cannot use a linguistic concept before they understand it cognitively (1)\n• Example: children do not use consistent tense markers before they grasp time as a concept (1)\n• Limitation: some studies suggest language influences cognition rather than simply reflecting it (Vygotsky) (1)' },
      { q: 'Explain Vygotsky\'s Zone of Proximal Development applied to language.', marks: 4, markScheme: '• ZPD = the gap between what a learner can do alone and what they can do with guidance (1)\n• In language, the caregiver models forms slightly beyond the child\'s independent production (1)\n• Scaffolding within the ZPD accelerates development (1)\n• Fades as competence grows — internalisation of the support (1)' },
      { q: 'Using an example, explain what a virtuous error is and why it is theoretically important.', marks: 4, markScheme: '• Virtuous error — grammatical over-generalisation of a rule, e.g. "mouses", "goed" (1)\n• The child has applied a regular rule to an irregular form (1)\n• Important: shows RULE-LEARNING rather than imitation (1)\n• Supports nativist / rule-based theories over pure behaviourism (1)' },
      { q: 'Describe an experimental design that could test a child\'s grasp of the regular plural morpheme.', marks: 6, markScheme: '• Invent a novel word, e.g. "wug" (1)\n• Show the child a picture and say "This is a wug" (1)\n• Show two and elicit: "Now there are two…?" (1)\n• Expected response "wugs" shows the child is applying the plural rule rather than reproducing memorised plurals (1)\n• This is the Berko "wug test" (1958) — evidence for productive rule knowledge (1)' },
      { q: 'Describe two common features of early pronunciation errors.', marks: 4, markScheme: '• Reduction of consonant clusters, e.g. "poon" for "spoon" (1)\n• Substitution of difficult sounds, e.g. /w/ for /r/ ("wed" for "red") (1)\n• Deletion of unstressed syllables, e.g. "nana" for "banana" (1)\n• Over-extension of favoured syllable shapes — reflects developing phonology (1)' },
      { q: 'Analyse the following transcript extract:\nChild (2.4): "Daddy gone shop."\nFather: "Yes, daddy\'s gone to the shop to get some milk."\nIdentify the child\'s stage and the father\'s scaffolding technique.', marks: 6, markScheme: '• Child is in the telegraphic stage — content words only, function words omitted (1)\n• Uses subject + past-participle + noun — shows correct word order (1)\n• Father recasts the utterance in full grammatical form (recasting) — providing a model without explicit correction (1)\n• Father expands semantically (adds "milk") — extending the exchange (1)\n• Both techniques are key features of Bruner\'s LASS (1)\n• Supports the interactionist view that modelling + scaffolding drive acquisition (1)' },
      { q: 'Explain two differences between Halliday\'s "instrumental" and "interactional" functions.', marks: 4, markScheme: '• Instrumental: getting what you need (e.g. requests for objects or actions) (1)\n• Interactional: maintaining social relationships (e.g. greetings, phatic tokens) (1)\n• Instrumental is goal-directed; interactional is relational (1)\n• Both emerge very early — show that pragmatic sophistication precedes grammatical maturity (1)' },
      { q: 'Describe two techniques commonly observed in caregivers\' child-directed speech.', marks: 4, markScheme: '• Recasting: repeating the child\'s utterance in grammatically correct form (1)\n• Expansion: adding information to the child\'s utterance (1)\n• Exaggerated intonation and pauses to invite turns (1)\n• Reference to the here-and-now via deictic pointing (1)' },
      { q: 'State two limitations of experimental studies of child language.', marks: 4, markScheme: '• Experimental settings are not natural — children may behave differently (1)\n• Samples are often small and culturally specific — limited generalisability (1)\n• Ethical constraints limit the duration and type of interventions possible (1)\n• Cannot directly observe mental representations — only output (1)' },
      { q: 'A child aged 3 says: "Me eat biscuit because I hungry." Identify two developmental features and two areas not yet mastered.', marks: 8, markScheme: '• Features present: subordinate clause introduced by "because" — evidence of post-telegraphic development (1 + 1)\n• Features present: ordering and tense forms roughly adult-like (1 + 1)\n• Not yet mastered: nominative "I" instead of "Me" (1 + 1)\n• Not yet mastered: copula ellipsis "I hungry" (missing "am") (1 + 1)' },
      { q: 'Compare Skinner\'s and Bruner\'s theories of language acquisition and evaluate which offers the stronger account.', marks: 10, markScheme: '• Skinner: behaviourist — imitation + reinforcement (1 + 1)\n• Criticism: cannot explain virtuous errors or novel utterances (1)\n• Bruner: interactionist LASS — explicit role of caregivers in scaffolding (1 + 1)\n• Strength: explains variation in acquisition linked to input quality (1)\n• Limit of Bruner alone: does not explain the internal mechanisms enabling rule extraction — Chomsky needed (1)\n• Most linguists now adopt a combined nativist + interactionist view (1)\n• Therefore Bruner offers a stronger account than Skinner alone but is best combined with nativist insights (1 + 1)' },
      { q: 'Evaluate: "Child language acquisition is primarily social, not innate." [15 marks]', marks: 15, markScheme: '• Social perspective (Bruner, Vygotsky): evidence from Genie and feral children suggests input is essential (2 + 2)\n• Halliday\'s functional framework shows language develops through interactional needs (2)\n• Innate perspective (Chomsky): poverty of the stimulus, universal grammar, critical period (2 + 2)\n• Virtuous errors show rule-learning that imitation cannot explain (2)\n• Interactionist synthesis: innate capacity + social input are BOTH necessary and complementary (2)\n• Therefore the statement overstates the social — a balanced evaluation is required (1)' },
      { q: 'Analyse how a caregiver might scaffold a 2-year-old\'s language over the course of a picture-book reading. Integrate at least three theorists. [20 marks]', marks: 20, markScheme: 'Up to 20 for integrated, example-led analysis.\n• Joint attention (Bruner) — caregiver and child focus on the same page (3)\n• Labelling routines reinforce lexis — Halliday\'s heuristic function (3)\n• Questions within the ZPD (Vygotsky): "what\'s this?" just beyond current competence (3)\n• Recasting and expansion — CDS techniques supporting form + meaning (3)\n• Phatic communion maintained through eye contact and affective pitch (2)\n• Piaget: concepts such as object permanence scaffolded via familiar characters (2)\n• Chomsky: innate capacity activated by comprehensible input (2)\n• Synthesis: a single picture-book interaction exemplifies nativist, interactionist and functional mechanisms simultaneously (2)' },
    ],
  },

  '1.4': {
    name: "Children's Written Language Development",
    questions: [
      { q: 'Name Kroll\'s four stages of writing development and give the approximate age for each.', marks: 4, markScheme: '• Preparation — up to about 6 years (1)\n• Consolidation — about 7–8 years (1)\n• Differentiation — about 9–10 years (1)\n• Integration — teenage years onwards (1)' },
      { q: 'Describe Kroll\'s "consolidation" stage and give one typical feature.', marks: 3, markScheme: '• Consolidation is where children\'s writing heavily resembles their speech (1)\n• Heavy coordination with "and" or "then" as main connectives (1)\n• Simple vocabulary, first-person perspective, limited punctuation (1)' },
      { q: 'State Britton\'s three functions of children\'s writing and give an example of each.', marks: 6, markScheme: '• Expressive — a diary entry, speech-like voice (1 + 1)\n• Transactional — a letter to the council informing/persuading (1 + 1)\n• Poetic — a crafted poem attending to form (1 + 1)' },
      { q: 'Describe Rothery\'s four genre categories and give a typical text type for each.', marks: 8, markScheme: '• Recount — chronological retelling (holiday recount) (1 + 1)\n• Report — factual generalised information (animal report) (1 + 1)\n• Narrative — orientation + complication + resolution (adventure story) (1 + 1)\n• Observation/comment — observation + evaluation (nature-walk note with "I thought it was pretty") (1 + 1)' },
      { q: 'A Year 3 writer uses coordination throughout. Why is this typical developmentally and how could a teacher scaffold towards greater complexity?', marks: 5, markScheme: '• Coordination reflects Kroll\'s consolidation stage — writing patterns follow speech (1)\n• The child may not yet have internalised the range of subordinators and connectors used in written mode (1)\n• Teacher can model complex sentences, introduce specific connectors ("because", "although", "after") (1)\n• Shared writing within the ZPD — jointly construct a paragraph with subordination (1)\n• Explicit genre pedagogy (Rothery) — show the expected structure of the target text (1)' },
      { q: 'Identify four features that distinguish "integration" stage writing from earlier stages.', marks: 4, markScheme: '• Range of sentence types — simple, compound, complex, non-finite (1)\n• Conscious register adjustment between genres and audiences (1)\n• Strong cohesion — varied connectives, pronoun reference, lexical chains (1)\n• Evidence of evaluation / modality / stance (1)' },
      { q: 'State two limitations of stage models (e.g. Kroll) for describing children\'s writing development.', marks: 4, markScheme: '• Individual variation — children do not progress at identical rates (1)\n• Cultural / socio-economic / educational factors strongly affect trajectories (1)\n• Children can be at different stages across different genres (Britton) (1)\n• Stages are descriptive tendencies rather than deterministic (1)' },
      { q: 'Describe the "pre-phonetic" or "pre-communicative" stage of spelling.', marks: 3, markScheme: '• Letter-like marks without systematic sound-letter mapping (1)\n• The child knows writing uses symbols but not yet how they correspond to sounds (1)\n• Can include random letter strings or repeated shapes (1)' },
      { q: 'Describe the "phonetic" stage of spelling with an example.', marks: 3, markScheme: '• Child spells words as they sound — sound-letter mapping is applied systematically (1)\n• Example: "cum" for "come", "wot" for "what" (1)\n• Virtuous errors here are evidence of rule-learning — compare with virtuous errors in speech (1)' },
      { q: 'Identify three typical features of early narrative writing by young children.', marks: 3, markScheme: '• Coordination with "and then" as the main connective (1)\n• First-person or third-person with little shifting of perspective (1)\n• Simple past tense and limited evaluative language (1)' },
      { q: 'Analyse the following Year 2 writing:\n"i went to the prk and i saw a dog and i had ice cream."\nIdentify three developmental features and the relevant stage.', marks: 6, markScheme: '• No capitalisation of "I" or first word — orthographic conventions still developing (1)\n• "prk" for "park" — phonetic spelling stage (1)\n• Repeated coordination "and...and..." — Kroll consolidation stage (1)\n• Lowercase + simple past + expressive function (Britton) (1)\n• Child is writing as they speak — typical of this age (1)\n• Teacher target: start to introduce variation, capitalisation and subordination within the ZPD (1)' },
      { q: 'Using Rothery\'s genre framework, identify the genre of the following student text and its stage in developmental terms:\n"Penguins are birds. They live in cold places. They eat fish."', marks: 4, markScheme: '• Genre: report — factual, generalised information (1)\n• Use of third-person plural and present tense (generalised truths) (1)\n• Simple sentences — typical of consolidation/early differentiation (1)\n• Development target: add elaboration (e.g. relative clauses, causal connectors) to move towards integration (1)' },
      { q: 'Explain why explicit teaching of genre (Rothery / Sydney School) is considered especially important for children from homes with less exposure to school literacies.', marks: 5, markScheme: '• Some genres (report, argument, recount) are not naturally acquired from conversation (1)\n• Children from homes with high book/essay exposure enter school already familiar with written conventions (1)\n• Those without such exposure face an unfair disadvantage if genres are not taught explicitly (1)\n• Explicit genre pedagogy makes school-valued forms accessible to all learners (1)\n• Addresses educational equity as well as linguistic development (1)' },
      { q: 'Describe two ways in which digital communication may affect children\'s written language development.', marks: 4, markScheme: '• Introduces new orthographic features — abbreviations ("brb"), emoji, creative capitalisation (1)\n• Encourages audience awareness — children adjust register for different platforms (1)\n• Research (Crystal, Tagg) shows digital does not typically replace standard writing in educated users — it ADDS a register (1)\n• Risk: inequality of digital access can widen gaps (1)' },
      { q: 'Explain two reasons why punctuation is often unstable in early writing.', marks: 4, markScheme: '• Punctuation is a written convention not reflected in speech — must be learned (1)\n• Children often use punctuation to mark prosody (pauses) rather than syntactic boundaries (1)\n• Full-stop placement depends on a developed sense of sentence — still emerging (1)\n• Teacher feedback typically moves from local (spelling) to global (cohesion, paragraphing) as competence grows (1)' },
      { q: 'Analyse a Year 6 narrative opening: "Darkness fell across the city, silent but for a single, flickering streetlight. Mia had been waiting." Identify three developmental features.', marks: 6, markScheme: '• Fronted adverbial "Darkness fell across the city…" — deliberate stylistic choice (1)\n• Complex noun phrase "a single, flickering streetlight" — multiple pre-modifiers (1)\n• Past perfect "had been waiting" — tense variation creating prior narrative time (1)\n• Minor sentence fragments ("silent but for…") — crafted rhythm (1)\n• Evidence of Kroll\'s differentiation/integration stage — Britton\'s poetic function dominant (1)\n• Shows developing control of the textual metafunction and genre expectations of literary narrative (1)' },
      { q: 'Compare two invented Year 2 writing samples: (a) coordination-heavy recount (b) short report with simple sentences. Suggest teaching priorities for each.', marks: 8, markScheme: '• (a): teach variation — subordinators ("because", "when"), cohesive pronouns, time connectives (1 + 1)\n• (a): genre-appropriate (recount strong) but build towards differentiation (1)\n• (b): teach elaboration — relative clauses, adjectives, adverbials of time/place (1 + 1)\n• (b): genre conventions solid; build toward fuller, more detailed reports (1)\n• Both children need explicit writing modelling in the ZPD (1 + 1)' },
      { q: 'Evaluate the value of using multiple frameworks (Kroll, Britton, Rothery, Halliday) when analysing children\'s writing. [10 marks]', marks: 10, markScheme: '• Kroll provides a developmental stage view (1 + 1)\n• Britton adds functional perspective — what the child is doing with the writing (1 + 1)\n• Rothery adds genre structure awareness (1 + 1)\n• Halliday\'s metafunctions integrate ideational + interpersonal + textual insight (1 + 1)\n• Using them together triangulates development — each offers a partial lens (1)\n• Top-band answers select and synthesise rather than mechanically list (1)' },
      { q: 'Discuss how a teacher might use Vygotsky\'s ZPD to plan a sequence of writing lessons on persuasive writing for Year 5. [10 marks]', marks: 10, markScheme: '• Assessment-for-learning to establish current competence — baseline writing task (1 + 1)\n• Modelled writing — teacher composes in front of class, thinking aloud (1 + 1)\n• Shared writing — class contributes, teacher scaffolds (1 + 1)\n• Guided writing in small groups — support withdrawn progressively (1 + 1)\n• Independent writing with success criteria — learner internalises the structure (1 + 1)' },
      { q: 'Compose a 500-word essay plan evaluating: "Children\'s writing development is best understood as a combination of stage, function and genre." [20 marks]', marks: 20, markScheme: 'Indicative plan, up to 20:\n• Intro: acknowledge that writing development is multi-faceted and that no single framework is sufficient (2)\n• Kroll: stage-based description of growing control — strengths and limits (3)\n• Britton: functional perspective — expressive/transactional/poetic — showing children can be at different stages across functions (3)\n• Rothery: genre framework — explicit teaching; equity argument (3)\n• Halliday: metafunctional integration (2)\n• Critical evaluation — individual variation, cultural factors, digital mode (3)\n• Conclusion: combined frameworks give the fullest picture; one framework alone is reductive (2)\n• Integration of examples (invented children\'s texts analysed) (2)' },
    ],
  },

};
